import os
from datetime import datetime

class FileNode:
    def __init__(self, name, is_file=False):
        self.name = name
        self.is_file = is_file
        self.creation_time = datetime.now()
        self.modification_time = datetime.now()
        self.permissions = 'rwxr-xr-x'  # Default permissions
        self.size = 0 if is_file else 0
        self.content = '' if is_file else None

class DirectoryNode(FileNode):
    def __init__(self, name):
        super().__init__(name)
        self.children = {}
        self.is_file = False

    def add_child(self, child_node):
        self.children[child_node.name] = child_node

    def remove_child(self, child_name):
        if child_name in self.children:
            del self.children[child_name]
            return True
        return False

    def list_children(self):
        return self.children.values()

    def get_child(self, name):
        return self.children.get(name)

class FileSystem:
    def __init__(self):
        self.root = DirectoryNode('')
        self.current_dir = self.root

    def navigate_path(self, path):
        if path == '/':
            self.current_dir = self.root
        else:
            parts = path.strip('/').split('/')
            current = self.root
            for part in parts:
                if part:
                    if part in current.children and isinstance(current.children[part], DirectoryNode):
                        current = current.get_child(part)
                    else:
                        raise FileNotFoundError(f"Path {path} not found")
            self.current_dir = current

    def cd(self, path):
        if path == '/':
            self.current_dir = self.root
        elif path == '..':
            if self.current_dir != self.root:
                parent = self.get_parent_of_current_dir()
                self.current_dir = parent if parent else self.root
        else:
            self.navigate_path(path)

    def get_parent_of_current_dir(self):
        if self.current_dir == self.root:
            return None
        path_list = self.get_current_path().split('/')
        parent_path = '/'.join(path_list[:-1]) if path_list else '/'
        return self.get_directory_by_path(parent_path)

    def get_directory_by_path(self, path):
        if path == '/':
            return self.root
        parts = path.strip('/').split('/')
        current = self.root
        for part in parts:
            if part:
                if part in current.children and isinstance(current.children[ = DirectoryNode:
                    current = current.get_child(part)
                else:
                    raise FileNotFoundError(f"Directory {path} not found")
        return current

    def ls(self):
        return self.current_dir.list_children()

    def mkdir(self, path):
        parts = path.strip('/').split('/')
        parent = self.get_directory_by_path('/'.join(parts[:-1]) if parts else self.root
        if parts[-1] in parent.children:
            raise FileExistsError(f"Directory {path} already exists")
        new_dir = DirectoryNode(parts[-1])
        parent.add_child(new_dir)
        return new_dir

    def rmdir(self, path):
        parts = path.strip('/').split('/')
        parent = self.get_directory_by_path('/'.join(parts[:-1]) if parts else self.root
        if parts[-1] not in parent.children or not isinstance(parent.children[parts[-1]], DirectoryNode):
            raise FileNotFoundError(f"Directory {path} not found")
        parent.remove_child(parts[-1])
        return True

    def pwd(self):
        return self.get_current_path()

    def get_current_path(self):
        path = []
        current = self.current_dir
        while current != self.root:
            path.append(current.name)
            current = current.parent if hasattr(current, 'parent') else self.root.parent
        return '/' + '/'.join(path)

    def create_file(self, path, content=''):
        parts = path.strip('/').split('/')
        parent = self.get_directory_by_path('/'.join(parts[:-1]) if parts else self.root)
        if parts[-1] in parent.children and isinstance(parent.children[parts[-1]], FileNode):
            raise FileExistsError(f"File {path} already exists")
        new_file = FileNode(parts[-1], is_file=True)
        new_file.content = content
        new_file.modification_time = datetime.now()
        parent.add_child(new_file)
        return new_file

    def remove_file(self, path):
        parts = path.strip('/').split('/')
        parent = self.get_directory_by_path('/'.join(parts[:-1]) if parts else self.root)
        if parts[-1] not in parent.children or isinstance(parent.children[parts[-1]], DirectoryNode):
            raise FileNotFoundError(f"File {path} not found")
        parent.remove_child(parts[-1])
        return True

    def file_details(self, path):
        parts = path.strip('/').split('/')
        parent = self.get_directory_by_path('/'.join(parts[:-1]) if parts else self.root)
        child = parent.get_child(parts[-1])
        if not child:
            raise FileNotFoundError(f"File {path} not found")
        if isinstance(child, FileNode):
            return {
                'name': child.name,
                'type': 'file',
                'creation_time': child.creation_time,
                'modification_time': child.modification_time,
                'permissions': child.permissions,
                'size': child.size,
                'content': child.content
            }
        else:
            raise IsADirectoryError(f"{path} is a directory")

