import re

def run(source):
    current_working_dir = os.getcwd()

    def create(name, content):
        with open(f'{current_working_dir}/{name}', 'w') as f:
            f.write(content)

    def read(name):
        try:
            with open(f'{current_working_dir}/{name}') as f:
                print(f.read())
        except FileNotFoundError:
            pass

    def append(name, text):
        with open(f'{current_working_dir}/{name}', 'a') as f:
            f.write(f'\n{text}')

    def count(name):
        try:
            with open(f'{current_working_dir}/{name}') as f:
                print(sum(1 for _ in f))
        except FileNotFoundError:
            pass

    def copy(src, dst):
        src_path = os.path.join(current_working_dir, src)
        dst_path = os.path.join(current_working_dir, dst)
        try:
            os.copy(src_path, dst_path)
        except FileNotFoundError:
            print(f"Source file '{src}' not found.")

    def make_directory(name):
        try:
            os.makedirs(os.path.join(current_working_dir, name))
        except FileExistsError:
            pass

    def move(src, dest):
        src_path = os.path.join(current_working_dir, src)
        dest_path = os.path.join(current_working_dir, dest)
        try:
            os.rename(src_path, dest_path)
        except (FileNotFoundError, PermissionError):
            print(f"Could not move '{src}' to '{dest}'. Source or destination may not exist.")

    def list_files():
        for file in os.listdir(current_working_dir):
            print(file)

    def list_files_in_dir(directory):
        dir_path = os.path.join(current_working_dir, directory)
        for file in os.listdir(dir_path):
            print(file)

    def find(pattern):
        for file in os.listdir(current_working_dir):
            if re.search(pattern, file):
                print(file)

    def delete(name):
        name_parts = name.split(' confirm')
        if len(name_parts) == 1:
            print("REFUSED")
        else:
            try:
                os.remove(os.path.join(current_working_dir, name_parts[0]))
            except FileNotFoundError:
                print(f"File '{name}' not found.")

    intents = source.split('\n')

    for intent in intents:
        command_parts = re.match(r'^(\w+)\s*(.*)$', intent)
        cmd = command_parts.group(1)
