            search_term = line.split('"')[1].strip()
            try:
                files = os.listdir()
                matches = [f for f in files if search_term in f]
                sorted_matches = sorted(matches)
                if sorted_matches:
                    print(' '.join(sorted_matches))
                else:
                    print('(none)')
            except FileNotFoundError:
                pass

