            if ' confirm' not in line:
                print('REFUSED')
            else:
                try:
                    os.remove(filename)
                except FileNotFoundError:
                    pass

        elif line.startswith('if '):
            parts = line.split(' then ')
            condition = parts[0][3:]  # Remove 'if '
            consequence = parts[1].strip()
            alternative = input()  # Not really, but we'll handle the line properly

            # Check if the file exists
            cond_file = condition
            if os.path.exists(cond_file):
                # Process the consequence
                handle_command(consequence)
            else:
                # Process the alternative
                handle_command(alternative)

    for line in source.split('\n'):
        handle_command(line.strip())

