            copy_match = re.match(r'^copy\s+(\S+)\s+to\s+(\S+)$', line)
            if copy_match:
                src, dst = copy_match.group(1), copy_match.group(2)
                try:
                    os.system(f'cp {src} {dst}')
                except Exception as e:
                    print(f"Copy failed: {e}")

