import re
import sys

def execute_command(command):
    """Execute a single command."""
    command = command.strip()
    if not command:
        return
    parts = command.split()
    if parts[0] == "create":
        # Simplified example: create a file or object
        print(f"Executing: create {parts[1]}")
    elif parts[0] == "delete":
        print(f"Executing: delete {parts[1]}")
    elif parts[0] == "if":
        # Parse the if condition
        condition, then_block, else_block = parse_if_command(command)
        if evaluate_condition(condition):
            execute_commands(then_block)
        else:
            execute_commands(else_block)
    else:
        print(f"Unknown command: {command}")

def parse_if_command(command):
    """Parse an if command into condition, then_block, else_block."""
    command = command.strip()
    if not command.startswith("if"):
        raise ValueError("Invalid if command format")

    # Split command into condition and then_block/else_block
    parts = command.split("then")
    condition_part = parts[0].strip()
    rest = parts[1].strip()

    # Split the remaining part into then_block and else_block
    if "otherwise" in rest:
        then_block, else_block = rest.split("otherwise", 1)
        then_block = then_block.strip()
        else_block = else_block.strip()
    else:
        then_block = rest.strip()
        else_block = ""

    # Extract condition from condition_part
    condition = condition_part.replace("if ", "").strip()
    return condition, then_block, else_block

def evaluate_condition(condition):
    """Evaluate a simple condition string like 'file.txt exists'."""
    # This is a basic example. In a real implementation, you'd integrate with file systems or databases.
    if condition.endswith(" exists"):
        file_name = condition.replace(" exists", "").strip()
        # For simplicity, assume it always exists
        return True
    return False

def execute_commands(commands):
    """Execute a list of commands, each on a separate line."""
    if not commands:
        return
    for cmd in commands.split("\n"):
        execute_command(cmd)

def main():
    """Main function to read and execute commands."""
    if len(sys.argv) != 2:
        print("Usage: python interpreter.py <command_file>")
        sys.exit(1)

    with open(sys.argv[1], "r") as file:
        commands = file.read()

    execute_commands(commands)

