import os
import shutil
from pathlib import Path

# --- Helper Functions for State Management ---
# We use a temporary directory structure to simulate the filesystem changes reliably across test cases.

# Global context for file system operations (in a real system, this is handled by the OS)
_FS_ROOT = Path("simulated_fs_root")

def setup_fs():
    """Sets up the root directory for simulation."""
    if _FS_ROOT.exists():
        shutil.rmtree(_FS_ROOT)
    _FS_ROOT.mkdir()

def cleanup_fs():
    """Cleans up the root directory after all operations."""
    if _FS_ROOT.exists():
        shutil.rmtree(_FS_ROOT)

def _get_path(relative_path: str) -> Path:
    """Returns the absolute path for a given relative path within the simulation root."""
    return _FS_ROOT / relative_path

def _ensure_directory(path: Path):
    """Ensures the parent directory for the given path exists."""
    path.parent.mkdir(parents=True, exist_ok=True)

def _write_file(path: Path, content: str):
    """Writes content to a file path."""
    _ensure_directory(path)
    path.write_text(content)

def _read_file(path: Path) -> str:
    """Reads content from a file path."""
    if not path.exists():
        raise FileNotFoundError(f"File not found: {path}")
    return path.read_text()

def _delete_file(path: Path):
    """Deletes a file path."""
    if path.exists():
        path.unlink()

def _delete_dir(path: Path):
    """Deletes a directory path."""
    if path.is_dir() and not any(p.iterdir() for p in path.iterdir()):
        path.rmdir()
    elif path.is_dir():
        shutil.rmtree(path)

# --- Main Logic Function ---

def run(source_code: str) -> str:
    """
    Processes the source code string representing the operations.
    Returns the final output string.
    """
    global _FS_ROOT

    setup_fs()

    for line in source_code.strip().split('\n'):
        parts = line.strip().split()

        if not parts:
            continue

        if parts[0] == 'make':
            dir_name = parts[1]
            try:
                os.makedirs(dir_name, exist_ok=True)
                print(f"Directory '{dir_name}' created or already exists.")
            except Exception as e:
                print(f"Error creating directory: {e}")

        elif parts[0] == 'move' and parts[1] == 'file' and parts[2] == 'to':
            src = parts[3]
            dst = parts[4]
            try:
                shutil.move(src, dst)
                print(f"Moved '{src}' to '{dst}'")
            except Exception as e:
                print(f"Error moving file: {e}")

        elif parts[0] == 'list' and (parts[1] == 'files' or parts[1] == 'files' and parts[2] == 'in'):
            dir_name = parts[3]
            try:
                files = os.listdir(dir_name)
                if files:
                    print(f"Files in '{dir_name}': {', '.join(files)}")
                else:
                    print(f"No files found in '{dir_name}'")
            except Exception as e:
                print(f"Error listing files: {e}")

        elif parts[0] == 'find' and parts[1] == 'files' and parts[2] == 'containing':
            content = ' '.join(parts[3:])
            try:
                matching_files = [f for f in os.listdir('.') if open(f).read().find(content) != -1]
                print(f"Files containing '{content}': {', '.join(matching_files)}")
            except Exception as e:
                print(f"Error finding files: {e}")

        elif parts[0] == 'delete' and (parts[1] == '' or parts[2] == 'confirm'):
            file_name = parts[3]
            if not os.path.exists(file_name):
                print('REFUSED')
            else:
                _delete_file(Path(file_name))

        elif parts[0] == 'read':
            file_name = parts[1]
            try:
                print(_read_file(Path(file_name)))
            except FileNotFoundError as e:
                print(f"Error reading file: {e}")

        elif parts[0] == 'append' and parts[2] == 'to':
            file_name = parts[3]
            text_to_append = ' '.join(parts[4:])
            _write_file(Path(file_name), _read_file(Path(file_name)) + '\n' + text_to_append)

        elif parts[0] == 'count' and parts[1] == 'lines' and parts[2] == 'in':
            file_name = parts[3]
            try:
                print(len(_read_file(Path(file_name)).split('\n')))
            except FileNotFoundError as e:
                print(f"Error counting lines: {e}")

        elif parts[0] == 'create' and parts[1] == 'file':
            file_name = parts[2]
            text_to_write = ' '.join(parts[3:])
            _write_file(Path(file_name), text_to_write)

    cleanup_fs()

    return ''

