            os.makedirs(path, exist_ok=True)

        elif intent == 'move' or intent == 'rename':
            src_path = current_dir / args[0]
            dest_path = current_dir / args[1]
            if src_path.is_file():
                shutil.move(str(src_path), str(dest_path))
            elif src_path.is_dir() and not dest_path.exists():
                os.rename(str(src_path), str(dest_path))

        elif intent == 'list files' or intent == 'ls':
            list_files(current_dir)

        elif intent == 'find files containing':
            find_files(current_dir, args[1])

        elif intent == 'delete' and not any('confirm' in t for t in tokens):
            print('REFUSED')

        elif intent == 'delete' and 'confirm' in tokens:
            path = current_dir / args[0]
            if path.is_file():
                path.unlink()
            elif path.is_dir():
                shutil.rmtree(path)

        elif intent == 'if':
            if pathlib.Path(args[0]) is not None and args[2]:
                run(args[2])
            else:
                run(args[3])

