import os
import re
from typing import Union

def run(source: str) -> None:
    commands = source.split("\n")
    current_dir = "."

    for command in commands:
        if command.startswith("create file"):
            create_file(command)
        elif command.startswith("read file"):
            read_file(command, current_dir)
        elif command.startswith("append to file"):
            append_to_file(command)
        elif command.startswith("count lines in file"):
            count_lines(command, current_dir)
        elif command.startswith("copy file"):
            copy_file(command)
        elif command == "make directory":
            make_directory(command)
        elif command.startswith("move file"):
            move_file(command)
        elif command.startswith("list files") or command.endswith(" in"):
            list_files(command, current_dir)
        elif command.startswith("find files containing"):
            find_files(command)
        elif command.startswith("delete file"):
            delete_file(command)
        elif command.startswith("delete file confirm"):
            delete_file_confirmed(command)
        elif command.startswith("if file exists"):
            if_exists(command)
        else:
            raise ValueError(f"Unknown command: {command}")

def create_file(command: str) -> None:
    match = re.match(r'create file (?P<filename>[^ ]+) with content "(?P<content>.*)"', command)
    if match:
        filename, content = match.group("filename"), match.group("content")
        with open(filename, "w") as f:
            f.write(content)

def read_file(command: str, current_dir: Union[str, None] = None) -> None:
    match = re.match(r'read file (?P<filename>[^ ]+)', command)
    if match:
        filename = match.group("filename")
        if current_dir is None:
            current_dir = "."
        try:
            with open(os.path.join(current_dir, filename), "r") as f:
                print(f.read())
        except FileNotFoundError:
            print(f"File '{filename}' not found.")

def append_to_file(command: str) -> None:
    match = re.match(r'append to file (?P<filename>[^ ]+) content "(?P<content>.*)"', command)
    if match:
        filename, content = match.group("filename"), match.group("content")
        with open(filename, "a") as f:
            f.write(f"\n{content}")

def count_lines(command: str, current_dir: Union[str, None] = None) -> None:
    match = re.match(r'count lines in file (?P<filename>[^ ]+)', command)
    if match:
        filename = match.group("filename")
        if current_dir is None:
            current_dir = "."
        try:
            with open(os.path.join(current_dir, filename), "r") as f:
                print(len(f.readlines()))
        except FileNotFoundError:
            print(f"File '{filename}' not found.")

def copy_file(command: str) -> None:
    match = re.match(r'copy file (?P<src>[^ ]+) to (?P<dst>[^ ]+)', command)
    if match:
        src, dst = match.group("src"), match.group("dst")
        shutil.copyfile(os.path.join(current_dir, src), os.path.join(current_dir, dst))

def make_directory(command: str) -> None:
    if not os.path.exists(os.path.join(current_dir, command[len("make directory "):])):
        os.mkdir(os.path.join(current_dir, command[len("make directory "):]))

def move_file(command: str) -> None:
    match = re.match(r'move file (?P<src>[^ ]+) to (?P<dst>[^ ]+)', command)
    if match:
        src, dst = match.group("src"), match.group("dst")
        shutil.move(os.path.join(current_dir, src), os.path.join(current_dir, dst))

def list_files(command: str, current_dir: Union[str, None] = None) -> None:
    if command.endswith(" in"):
        dirname = command[:-len(" in")]
    else:
        dirname = current_dir
    files = os.listdir(dirname)
    print(" ".join(sorted(files)) or "(empty)")

def find_files(command: str) -> None:
    match = re.match(r'find files containing (?P<text>[^ ]+)', command)
    if match:
        text = match.group("text")
        files = [f for f in os.listdir(".") if re.search(re.escape(text), f)]
        print(" ".join(sorted(files)) or "(none)")

def delete_file(command: str) -> None:
    match = re.match(r'delete file (?P<filename>[^ ]+)', command)
    if match:
        filename = match.group("filename")
        if not os.path.exists(os.path.join(current_dir, filename)):
            print(f"File '{filename}' not found.")
        elif "confirm" in command:
            delete_file_confirmed(command)
        else:
            print("REFUSED")

def delete_file_confirmed(command: str) -> None:
    match = re.match(r'delete file confirm (?P<filename>[^ ]+)', command)
    if match:
        filename = match.group("filename")
        os.remove(os.path.join(current_dir, filename))

def if_exists(command: str) -> None:
    match = re.match(r'if (?P<filename>[^ ]+) exists then (?P<intent>.*) otherwise (?P<alternate_intent>.*)', command)
    if match:
        filename, intent, alternate_intent = match.group("filename"), match.group("intent"), match.group("alternate_intent")
        if os.path.exists(os.path.join(current_dir, filename)):
            run(f"{intent}\n")
        else:
            run(f"{alternate_intent}\n")

import sys
import os

def read_file(filename):
    """Read and print the contents of a file."""
    try:
        with open(filename, 'r') as f:
            print(f.read())
    except FileNotFoundError:
        print(f"Error: File '{filename}' not found.")
    except Exception as e:
        print(f"Error reading file '{filename}': {e}")

def delete_file(filename):
    """Delete the specified file."""
    try:
        os.remove(filename)
        print(f"File '{filename}' deleted successfully.")
    except FileNotFoundError:
        print(f"Error: File '{filename}' not found.")
    except Exception as e:
        print(f"Error deleting file '{filename}': {e}")

def execute_command(command_str):
    """
    Execute a command string. Supports nested commands.

    Args:
        command_str (str): A string representing a single command.
    """
    if not command_str.strip():
        return

    parts = command_str.strip().split()

    if parts[0] == 'if':
        # Parse the if command
        if len(parts) < 6 or parts[2] != 'exists':
            print("Error: Invalid 'if' command syntax.")
            return

        filename = parts[1]
        then_start = parts.index('then') + 1
        then_end = parts.index('otherwise')
        then_cmd = ' '.join(parts[then_start:then_end])
        else_cmd = ' '.join(parts[then_end + 1:])

        if os.path.exists(filename):
            execute_command(then_cmd)
        else:
            execute_command(else_cmd)

    elif parts[0] == 'read':
        if len(parts) < 2:
            print("Error: Missing filename in 'read' command.")
        else:
            read_file(parts[1])

    elif parts[0] == 'delete':
        if len(parts) < 2:
            print("Error: Missing filename in 'delete' command.")
        else:
            delete_file(parts[1])

    else:
        print(f"Unknown command: '{parts[0]}'")

def main():
    """Main function to process input commands from stdin."""
    for line in sys.stdin:
        line = line.strip()
        if line:
            execute_command(line)

if __name__ == "__main__":
    main()

