        match = re.match(r'read (\S+)', line)
        if match:
            filename = match.group(1)
            if os.path.exists(filename) and os.path.isfile(filename):
                try:
                    with open(filename, 'r') as f:
                        content = f.read()
                    print(f'Content of "{filename}":\n{content}')
                except Exception as e:
