                    print(f'Error appending to file "{filename}": {e}')
            else:
                print(f'File "{filename}" not found or not a file.')
            continue

        # Move file to destination
        match = re.match(r'move (\S+) to (\S+)', line)
        if match:
            src, dest = match.group(1), match.group(2)
            if os.path.exists(src) and os.path.isfile(src):
                try:
                    shutil.move(src, dest)
                    print(f'Moved file "{src}" to "{dest}"')
                except Exception as e:
                    print(f'Error moving file "{src}": {e}')
            else:
                print(f'File "{src}" not found or not a file.')
            continue

        # Make directory
        match = re.match(r'make directory (\S+)', line)
        if match:
