                    print(f'Error listing files in "{dir_name}": {e}')
            else:
                print(f'Directory "{dir_name}" not found or not a directory.')
            continue

        # Delete file with confirmation
        match = re.match(r'delete (\S+)(?: confirm)?', line)
        if match:
            filename = match.group(1)
            if 'confirm' in line:
                if os.path.exists(filename) and os.path.isfile(filename):
                    try:
                        os.remove(filename)
                        print(f'Deleted file "{filename}"')
                    except Exception as e:
                        print(f'Error deleting file "{filename}": {e}')
                else:
                    print(f'File "{filename}" not found or not a file.')
            else:
                print(f'REFUSED: Cannot delete "{filename}" without confirmation.')
            continue

        # Unknown command
        print(f'Unknown command: {line}')

