import os
import re

def process_line(line):
    line = line.strip()
    if not line:
        return

    if line.startswith('create file '):
        match = re.match(r'create file ([^ ]+) with content "(.+)"', line)
        if match:
            filename, content = match.groups()
            with open(filename, 'w') as f:
                f.write(content)
            print(f"Created file '{filename}' with content: {content}")
        else:
            print("Invalid 'create file' command.")

    elif line.startswith('read file '):
        parts = line.split(' ', 1)
        if len(parts) < 2:
            print("Invalid 'read file' command.")
            return
        filename = parts[1]
        try:
            with open(filename, 'r') as f:
                content = f.read()
            print(f"Content of '{filename}':\n{content}")
        except FileNotFoundError:
            print(f"File '{filename}' not found.")
        except Exception as e:
            print(f"Error reading file '{filename}': {e}")

    elif line.startswith('append "'):
        parts = line.split(' ', 2)
        if len(parts) < 3:
            print("Invalid 'append' command.")
            return
        text = parts[1][1:-1]  # Remove quotes
        filename = parts[2]
        try:
            with open(filename, 'a') as f:
                f.write(text)
            print(f"Appended '{text}' to '{filename}'")
        except FileNotFoundError:
            print(f"File '{filename}' not found.")
        except Exception as e:
            print(f"Error appending to file '{filename}': {e}")

    elif line.startswith('copy '):
        parts = line.split(' ', 3)
        if len(parts) < 4:
            print("Invalid 'copy' command.")
            return
        source = parts[2]
        destination = parts[3]
        try:
            with open(source, 'r') as src:
                content = src.read()
            with open(destination, 'w') as dst:
                dst.write(content)
            print(f"Copied content from '{source}' to '{destination}'")
        except FileNotFoundError:
            print(f"File '{source}' not found.")
        except Exception as e:
            print(f"Error copying from '{source}': {e}")

    elif line.startswith('make directory '):
        directory = line.split(' ', 1)[1]
        try:
            os.makedirs(directory, exist_ok=True)
            print(f"Directory '{directory}' created successfully.")
        except Exception as e:
            print(f"Error creating directory '{directory}': {e}")

    elif line.startswith('move '):
        parts = line.split(' ', 3)
        if len(parts) < 4:
            print("Invalid 'move' command.")
            return
        source = parts[2]
        destination = parts[3]
        try:
            os.rename(source, destination)
            print(f"Moved '{source}' to '{destination}'")
        except FileNotFoundError:
            print(f"File '{source}' not found.")
        except Exception as e:
            print(f"Error moving '{source}': {e}")

    elif line == 'list files':
        try:
            files = os.listdir('.')
            if files:
                print("Files in current directory:")
                for f in files:
                    print(f)
            else:
                print("No files found.")
        except Exception as e:
            print(f"Error listing files: {e}")

    elif line.startswith('find files containing "'):
        parts = line.split(' ', 2)
        if len(parts) < 3:
            print("Invalid 'find files containing' command.")
            return
        text = parts[2][1:-1]  # Remove quotes
        found_files = []
        try:
            for filename in os.listdir('.'):
                try:
                    with open(filename, 'r') as f:
                        content = f.read()
                        if text in content:
                            found_files.append(filename)
                except:
                    continue
            if found_files:
                print("Files containing the text:")
                for f in found_files:
                    print(f)
            else:
                print("No files found containing the text.")
        except Exception as e:
            print(f"Error searching for files: {e}")

    elif line.startswith('delete '):
        filename = line.split(' ', 1)[1]
        try:
            os.remove(filename)
            print(f"File '{filename}' deleted.")
        except FileNotFoundError:
            print(f"File '{filename}' not found.")
        except Exception as e:
            print(f"Error deleting file '{filename}': {e}")

    elif line.startswith('if '):
        print("Conditional commands are not fully implemented in this version.")

    else:
        print(f"Unknown command: {line}")

