            try:
                with open(filename, 'r') as f:
                    content = f.read()
                print(content)
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

    # Append to file
    elif cmd.startswith('append "'):
        match = re.match(r'append "(.+)" to ([^ ]+)', cmd)
        if match:
            text, filename = match.groups()
            try:
                with open(filename, 'a') as f:
                    f.write(text + '\n')
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

    # Count lines in file
    elif cmd.startswith('count lines in '):
