            try:
                with open(filename, 'r') as f:
                    lines = f.readlines()
                print(len(lines))
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

    # Copy file
    elif cmd.startswith('copy '):
        match = re.match(r'copy ([^ ]+) to ([^ ]+)', cmd)
        if match:
            source, destination = match.groups()
            try:
                shutil.copyfile(source, destination)
            except FileNotFoundError:
                print(f"File '{source}' not found.")

    # Make directory
    elif cmd.startswith('make directory '):
        match = re.match(r'make directory ([^ ]+)', cmd)
        if match:
            directory = match.groups()[0]
            try:
                os.mkdir(directory)
            except FileExistsError:
                print(f"Directory '{directory}' already exists.")

    # Move file
    elif cmd.startswith('move '):
        match = re.match(r'move ([^ ]+) to ([^ ]+)', cmd)
        if match:
            source, destination = match.groups()
            try:
                shutil.move(source, destination)
            except FileNotFoundError:
                print(f"File '{source}' not found.")

    # List files
    elif cmd == 'list files':
        print(' '.join(list_files()))
    elif cmd.startswith('list files in '):
        match = re.match(r'list files in ([^ ]+)', cmd)
        if match:
            directory = match.groups()[0]
            print(' '.join(list_files(directory)))

    # Find files
    elif cmd.startswith('find files containing '):
        match = re.match(r'find files containing "(.+)"', cmd)
        if match:
            pattern = match.groups()[0]
            files = [f for f in list_files() if re.search(pattern, f)]
            print(' '.join(files) or '(none)')

    # Delete file
    elif cmd.startswith('delete ') or cmd == 'delete confirm':
        match = re.match(r'delete ([^ ]+)', cmd)
        if match:
            filename = match.groups()[0]
            if not cmd.endswith(' confirm'):
                print("REFUSED")
                return
            try:
                os.remove(filename)
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

    # If exists, then ... otherwise ...
    elif cmd.startswith('if '):
        match = re.match(r'if ([^ ]+) exists then', cmd)
        if match:
            filename = match.groups()[0]
            commands = cmd[len(match.groups()[0]) + len(" exists then"):].strip()
            if os.path.exists(filename):
                run_command(commands)
    elif cmd == '':
        pass
    else:
        print(f"Unknown command '{cmd}'.")

