import os

def make_dir(name):
    try:
        os.makedirs(name)
    except FileExistsError:
        pass

def move_file(src, dest):
    if not src or not dest:
        return

    shutil.copy2(src, dest)
    os.remove(src)

def list_files(directory='.'):
    files = sorted([f for f in os.listdir(directory) if os.path.isfile(os.path.join(directory, f))])
    return files or ["(empty)"]

def find_files(pattern):
    files = [f for f in os.listdir() if pattern in f]
    return files or ["(none)"]

def delete_file(name, confirm=False):
    if not name:
        return

    if confirm:
        try:
            os.remove(name)
        except FileNotFoundError:
            print("REFUSED")
    else:
        print("REFUSED")

def run_if(condition, then_intent, otherwise_intent):
    if os.path.isfile(condition):
        run(then_intent)
    else:
        run(otherwise_intent)

def run(source):
    lines = source.strip().split("\n")
    for line in lines:
        if line:
