import os
import shutil

def process_line(line):
    line = line.strip()
    if not line:
        return

    # Match 'make directory' command
    if re.match(r'^make directory ([^ ]+)$', line):
        dir_name = re.search(r'^make directory ([^ ]+)$', line).group(1)
        os.makedirs(dir_name, exist_ok=True)
        print(f"Directory '{dir_name}' created or already exists.")

    # Match 'move' command
    elif re.match(r'^move ([^ ]+) to ([^ ]+)$', line):
        src = re.search(r'^move ([^ ]+) to ([^ ]+)$', line).group(1)
        dest = re.search(r'^move ([^ ]+) to ([^ ]+)$', line).group(2)
        try:
            shutil.move(src, dest)
            print(f"Moved '{src}' to '{dest}'")
        except Exception as e:
            print(f"Error moving file: {e}")

    else:
        print(f"Unknown command: {line}")

def main():
    # Example input lines
    lines = [
        "make directory logs",
        "move m.txt to logs"
    ]

    for line in lines:
        process_line(line)

if __name__ == "__main__":
    main()

