import os
import shutil

def process_command(command: str):
    command = command.strip()
    if not command:
        return

    if command.startswith('create file'):
        _, _, filename, _, content = command.split(' with content ')
        content = content.strip('"')
        with open(filename, 'w') as f:
            f.write(content)
    elif command.startswith('read file'):
        filename = command.split(' ')[2]
        if os.path.exists(filename):
            with open(filename, 'r') as f:
                print(f.read())
    elif command.startswith('append'):
        _, text, filename = command.split(' to ')
        text = text.strip('"')
        filename = filename.strip()
        with open(filename, 'a') as f:
            f.write(text)
    elif command.startswith('count lines in'):
        filename = command.split(' ')[3]
        if os.path.exists(filename):
            with open(filename, 'r') as f:
                lines = f.readlines()
                print(len(lines))
    elif command.startswith('copy'):
        src, dst = command.split(' to ')
        src = src.strip()
        dst = dst.strip()
        shutil.copy(src, dst)
    elif command.startswith('move'):
        src, dst = command.split(' to ')
        src = src.strip()
        dst = dst.strip()
        shutil.move(src, dst)
    elif command.startswith('list files'):
        dir_name = command.split(' in ')[1] if ' in ' in command else '.'
        files = os.listdir(dir_name)
        files.sort()
        print('\n'.join(files))
    elif command.startswith('find files containing'):
        text = command.split(' containing ')[1].strip('"')
        dir_name = '.'
        matching_files = []
        for file in os.listdir(dir_name):
            file_path = os.path.join(dir_name, file)
            if os.path.isfile(file_path):
                with open(file_path, 'r') as f:
                    content = f.read()
                    if text in content:
                        matching_files.append(file)
        print('\n'.join(matching_files))
    elif command.startswith('delete'):
        parts = command.split()
        filename = parts[1]
        if len(parts) > 2 and parts[2] == 'confirm':
            try:
                os.remove(filename)
                print(f"File '{filename}' deleted.")
            except Exception as e:
                print(f"Error deleting '{filename}': {e}")
        else:
            print("Cannot delete without confirmation.")
    elif command.startswith('if'):
        parts = command.split(' then ')
        if len(parts) < 2:
            print("Invalid if command.")
            return
        condition_part, rest = parts
        condition_part = condition_part.strip()
        rest = rest.strip()
        if ' otherwise ' in rest:
            then_part, else_part = rest.split(' otherwise ')
        else:
            then_part = rest
            else_part = ''

        condition = condition_part.split(' exists ')[0].strip()
        exists = os.path.exists(condition)

        if exists:
            process_command(then_part)
        else:
            process_command(else_part)
    else:
        print(f"Unknown command: {command}")

