import os

def main():
    while True:
        command = input("file-shell> ").strip().lower()
        parts = command.split()

        if not parts:
            continue

        if parts[0] == "create":
            if len(parts) < 3:
                print("Invalid command. Use 'create file <filename> with content <content>' or 'create directory <dirname>'")
                continue
            if parts[1] == "file":
                if len(parts) < 6 or parts[3] != "with" or parts[4] != "content":
                    print("Invalid command. Use 'create file <filename> with content <content>'")
                    continue
                filename = parts[2]
                content = ' '.join(parts[5:])
                if os.path.exists(filename):
                    if os.path.isfile(filename):
                        print(f"File '{filename}' already exists. Replace it? (y/n)")
                        replace = input().strip().lower()
                        if replace == 'y':
                            with open(filename, 'w') as f:
                                f.write(content)
                            print(f"Replaced content of '{filename}'")
                        else:
                            print("Did not replace the file.")
                    else:
                        print(f"'{filename}' is a directory, not a file.")
                else:
                    with open(filename, 'w') as f:
                        f.write(content)
                    print(f"Created file '{filename}' with content: {content}")
            elif parts[1] == "directory":
                if len(parts) < 3:
                    print("Invalid command. Use 'create directory <dirname>'")
                    continue
                dirname = parts[2]
                if os.path.exists(dirname):
                    print(f"Directory '{dirname}' already exists.")
                else:
                    os.makedirs(dirname)
                    print(f"Created directory '{dirname}'")
            else:
                print("Invalid command. Use 'create file <filename> with content <content>' or 'create directory <dirname>'")

        elif parts[0] == "delete":
            if len(parts) < 2 or parts[1] != "file":
                print("Invalid command. Use 'delete file <filename>'")
                continue
            filename = parts[2]
            if os.path.isfile(filename):
                os.remove(filename)
                print(f"Deleted file '{filename}'")
            else:
                print(f"'{filename}' is not a file.")

        elif parts[0] == "list":
            if len(parts) < 2:
                print("Invalid command. Use 'list files', 'list directories', or 'list all'")
                continue
            if parts[1] == "files":
                files = [f for f in os.listdir() if os.path.isfile(f)]
                if not files:
                    print("No files found.")
                else:
                    print("Files:")
                    for f in files:
                        print(f"  - {f}")
            elif parts[1] == "directories":
                dirs = [d for d in os.listdir() if os.path.isdir(d)]
                if not dirs:
                    print("No directories found.")
                else:
                    print("Directories:")
                    for d in dirs:
                        print(f"  - {d}")
            elif parts[1] == "all":
                all_items = os.listdir()
                if not all_items:
                    print("No items found.")
                else:
                    print("All items:")
                    for item in all_items:
                        print(f"  - {item}")
            else:
                print("Invalid command. Use 'list files', 'list directories', or 'list all'")

        elif parts[0] == "help":
            print("Available commands:")
            print("  create file <filename> with content <content> - Create a file with content")
            print("  create directory <dirname> - Create a directory")
            print("  delete file <filename> - Delete a file")
            print("  list files - List all files")
            print("  list directories - List all directories")
            print("  list all - List all items (files and directories)")
            print("  help - Show this help message")
            print("  quit - Exit the shell")

        elif parts[0] == "quit":
            print("Exiting the shell. Goodbye!")
            break

        else:
            print("Invalid command. Type 'help' to see available commands.")

