import os
from typing import List

def list_files(directory: str = '.') -> List[str]:
    return sorted(os.listdir(directory)) if directory else []

def read_file(filename: str) -> str:
    with open(filename, 'r') as file:
        return '\n'.join(file.readlines())

def create_file(filename: str, content: str):
    with open(filename, 'w') as file:
        file.write(content)

def append_to_file(filename: str, text: str):
    with open(filename, 'a') as file:
        file.write(f"{text}\n")

def count_lines_in_file(filename: str) -> int:
    with open(filename, 'r') as file:
        return sum(1 for line in file)

def copy_file(src: str, dest: str):
    src_path = os.path.join('.', src)
    dest_path = os.path.join('.', dest)
    with open(src_path, 'r') as src_file, open(dest_path, 'w') as dest_file:
        dest_file.write(src_file.read())

def make_directory(dirname: str):
    os.makedirs(os.path.join('.', dirname), exist_ok=True)

def move_file(src: str, dest: str):
    src_path = os.path.join('.', src)
    if not os.path.exists(src_path):
        return "REFUSED"
    dest_path = os.path.join('.', dest)
    shutil.move(src_path, dest_path)

def find_files_containing(pattern: str) -> List[str]:
    results = []
    for filename in list_files():
        if pattern in read_file(filename):
            results.append(filename)
    return sorted(results)

def delete_file(filename: str, confirm: bool = False) -> str:
    if not confirm and not os.path.exists(os.path.join('.', filename)):
        return "REFUSED"
    file_path = os.path.join('.', filename)
    if not os.path.exists(file_path):
        return "REFUSED"
    os.remove(file_path)
    return ""

def run(source: str):
    intents = source.strip().split('\n')
    for intent in intents:
        parts = intent.strip().split()
        if not parts:
            continue
        command = parts[0].lower()
        args = parts[1:]

        # Print the observable result of read/list/count/find intents, in order, one per line.
        if command == 'read file':
            filename = args[0]
            print(read_file(filename))
        elif command == 'append' or command == 'copy' or command == 'move':
            print()  # Do not print anything for these intents (pure side-effects)
        elif command in ('count lines in', 'find files containing'):
            filename = args[0]
            if command == 'count lines in':
                print(count_lines_in_file(filename))
            else:
                print('\n'.join(find_files_containing(filename)))
        elif command == 'list files':
            print(' '.join(list_files()))
        elif command == 'make directory':
            make_directory(args[0])
        elif command in ('delete', 'move'):
            if len(args) < 2 or args[-1] != 'confirm':
                print("REFUSED")
                continue
            filename = args[0]
            delete_file(filename, confirm=True)
        else:
            create_file(args[0], ' '.join(args[1:]))
    print()

