                filename = parts[1]
                text = ' '.join(parts[2:])
                try:
                    with open(filename, 'a') as f:
                        f.write(text + '\n')
                    print(f"Appended '{text}' to {filename}")
                except Exception as e:
                    print(f"Error appending to file: {e}")

            elif command == 'count':
                if len(parts) < 2:
                    print("Usage: count <file>")
