                filename = parts[1]
                try:
                    with open(filename, 'r') as f:
                        lines = f.readlines()
                    print(f"Line count: {len(lines)}")
                except Exception as e:
                    print(f"Error counting lines: {e}")

            elif command == 'copy':
                if len(parts) < 3:
                    print("Usage: copy <src> <dest>")
