import os
import re
from typing import List, Union, Dict

FILE_SYSTEM: Dict[str, Union[None, str]] = {}
DIRECTORIES: set = {os.getcwd()}

def _ensure_directory(path: str) -> None:
    if path not in DIRECTORIES:
        DIRECTORIES.add(path)

def _get_fs_state() -> Dict[str, Union[None, str]]:
    return FILE_SYSTEM.copy()

def _set_file_content(filename: str, content: str) -> None:
    if filename not in FILE_SYSTEM or FILE_SYSTEM[filename] is None:
        FILE_SYSTEM[filename] = content

def _get_file_content(filename: str) -> Union[None, str]:
    return FILE_SYSTEM.get(filename)

def execute_command(line: str) -> List[str]:
    line = line.strip()

    # 1. Handle 'if/elif/else' blocks (Simplified State Machine approach)
    if line.startswith("IF_START"):
        return []  # Handled by the main loop flow

    elif line.startswith("ELSE_START"):
        return ["REFUSED"]  # Control flow end marker (for 'if' block failure)

    elif line.startswith("IF_END") or line.startswith("ELSE_END") or line.startswith("END"):
        return []  # Control flow end marker

    # 2. Simple Command Parsing (Using regex and structured checks)

    # --- Directory Management
    elif line == "list files":
        files = sorted(os.listdir(os.getcwd()))
        if not files:
            return ["(empty)"]
        return files

    elif line.startswith("make directory"):
        path = re.search(r"directory (.*?)", line).group(1)
        _ensure_directory(path)
        return []

    # --- File Management
    elif line.startswith("create file"):
        filename, content = re.search(r"file (.+?) with content \"(.+)\"" , line).groups()
        _set_file_content(filename, content)
        return []

    elif line.startswith("read file"):
        filename = re.search(r"file (.+)", line).group(1)
        content = _get_file_content(filename)
        if not content:
            return ["(empty)"]
        return [content]

    elif line.startswith("append"):
        filename, text = re.search(r"to (.+?) append \"(.+)\"" , line).groups()
        _set_file_content(filename, (_get_file_content(filename) or "") + "\n" + text)
        return []

    elif line.startswith("count lines in"):
        filename = re.search(r"in (.+?)", line).group(1)
        count = sum(1 for _ in _get_file_content(filename).splitlines())
        return [str(count)]

    elif line.startswith("copy"):
        src, dest = re.search(r"(.+?) to (.+)", line).groups()
        if os.path.exists(src):
            open(dest, "w").write(_get_file_content(src))
            return []
        else:
            return ["REFUSED"]

    elif line.startswith("move"):
        src, dest = re.search(r"(.+?) to (.+)", line).groups()
        if os.path.exists(src):
            try:
                os.rename(src, dest)
            except Exception as e:
                return ["REFUSED"]
            else:
                os.remove(src)
                return []
        else:
            return ["REFUSED"]

    # --- File Search Management
    elif line.startswith("find files containing"):
        text, *filenames = re.search(r"containing (.+?) in (.*?)", line).groups()
        matches = [filename for filename in filenames if _get_file_content(filename) and any(text in line for line in _get_file_content(filename).splitlines())]
        if not matches:
            return ["(none)"]
        return matches

    # --- Deletion Management
    elif line.startswith("delete"):
        name = re.search(r"(.+?)", line).group(1)
        if _get_file_content(name):
            if "confirm" in line:
                os.remove(name)
                return []
            else:
                return ["REFUSED"]
        elif not os.path.exists(name):
            return ["REFUSED"]

    # --- Conditional Statements Management
    elif line.startswith("if"):
        condition, *intent = line.split()
        if _get_file_content(condition):
            return execute_command(" ".join(intent))
        else:
            return execute_command(" ELSE_START " + "\n".join(intent) + "\n END ")

def run(source: str) -> None:
    lines = source.split("\n")
    result = []
    for line in lines:
        result += execute_command(line)
    print("\n".join(result))

