        print(f"Unknown command: {cmd_line}")

def main(source):
    lines = source.split('\n')
    for line in lines:
        line = line.strip()
        if not line:
            continue
        if line.startswith('if'):
            split_line = line.split(' then ')
            if len(split_line) < 2:
                print("Invalid if command")
                continue
            condition_part = split_line[0]
            rest = split_line[1]
            else_parts = rest.split(' otherwise ', 1)
            if len(else_parts) < 2:
                print("Invalid if command")
                continue
            then_part = else_parts[0]
            else_part = else_parts[1]

            condition_parts = condition_part.split()
            if len(condition_parts) != 2 or condition_parts[1] != 'exists':
                print("Invalid condition in if command")
                continue
            name = condition_parts[0]

            if os.path.exists(name):
                process_command(then_part)
            else:
                process_command(else_part)
        else:
            process_command(line)

