                        os.remove(name)
                        print(f"Deleted file: {name}")
                    except FileNotFoundError:
                        print(f"File '{name}' not found.")
                    except Exception as e:
                        print(f"Error deleting file: {name} - {str(e)}")
                else:
                    print("Use 'confirm' to delete files.")

        # Handle 'if' command (conditional execution)
        elif re.match(r'^if\s+.*$', line):
            match = re.match(r'^if\s+(.+?)\s+exists\s+then\s+(.+?)\s+otherwise\s+(.+)$', line)
            if match:
                condition = match.group(1)
                then_cmd = match.group(2)
                else_cmd = match.group(3)
                if os.path.exists(condition):
                    result = run(then_cmd + '\n')
                else:
                    result = run(else_cmd + '\n')
                return result

        # Default unknown command
        else:
            print(f"Unknown command: {line}")

