        if not parts:
            continue

        if parts[0] == 'create' and parts[1] == 'file':
            # 'create file <filename> "content"'
            filename = parts[2]
            content = ''.join(parts[3:-1]) if parts[-1].startswith('"') else ''
            if parts[-1].startswith('"') and parts[-1].endswith('"'):
                content = parts[-1][1:-1]
            with open(filename, 'w') as f:
                f.write(content)
            print(f"Created file: {filename}")

        elif parts[0] == 'append':
            if parts[2] == 'to':
                # 'append "content" to <filename>'
                content = parts[1].strip('"')
                filename = parts[3]
                with open(filename, 'a') as f:
                    f.write(content)
                print(f"Appended to file: {filename}")

        elif parts[0] == 'move' and parts[2] == 'to':
            # 'move <source> to <destination>'
            source = parts[1]
            destination = parts[3]
            try:
                os.rename(source, destination)
                print(f"Moved file: {source} → {destination}")
            except FileNotFoundError:
                print(f"Error: Source file '{source}' not found.")

        elif parts[0] == 'list' and parts[1] == 'files':
            # 'list files in <directory>'
            directory = parts[3] if len(parts) > 3 and parts[3] == 'in' else '.'
            try:
                files = os.listdir(directory)
                print(f"Files in directory '{directory}':")
                for file in files:
                    print(f"  - {file}")
            except Exception as e:
                print(f"Error: {e}")

        elif parts[0] == 'find' and parts[2] == 'containing':
            # 'find files containing "text"'
            text = parts[3].strip('"')
            try:
                for root, dirs, files in os.walk('.'):
                    for file in files:
                        file_path = os.path.join(root, file)
                        with open(file_path, 'r') as f:
                            if text in f.read():
                                print(f"Found in: {file_path}")
            except Exception as e:
                print(f"Error: {e}")

        elif parts[0] == 'if':
            # Simplified 'if' command: check if file exists
            condition = parts[1]
            if os.path.exists(condition):
                # Execute 'then' command (simplified)
                then_cmd = ' '.join(parts[4:])
                print(f"Condition true: Executing '{then_cmd}'")
            else:
                # Execute 'otherwise' command (simplified)
                otherwise_cmd = ' '.join(parts[4:])
                print(f"Condition false: Executing '{otherwise_cmd}'")

        else:
            print(f"Unknown command: {parts[0]}")

