import os
import re

def run(source):
    for line in source.splitlines():
        line = line.strip()
        if not line:
            continue

        # Match command: create file
        if re.match(r'^create file (\S+) with content "(.+)"$', line):
            match = re.match(r'^create file (\S+) with content "(.+)"$', line)
            filename = match.group(1)
            content = match.group(2)
            with open(filename, 'w') as f:
                f.write(content)
            print(f"Created file '{filename}' with content.")

        # Match command: read file
        elif re.match(r'^read file (\S+)$', line):
            match = re.match(r'^read file (\S+)$', line)
            filename = match.group(1)
            try:
                with open(filename, 'r') as f:
                    content = f.read()
                    print(f"File '{filename}':\n{content}")
            except FileNotFoundError:
                print(f"Error: File '{filename}' not found.")

        # Match command: append to file
        elif re.match(r'^append "(.+)" to (\S+)$', line):
            match = re.match(r'^append "(.+)" to (\S+)$', line)
            text = match.group(1)
            filename = match.group(2)
            try:
                with open(filename, 'a') as f:
                    f.write(text)
                print(f"Appended text to '{filename}'.")
            except Exception as e:
                print(f"Error appending to '{filename}': {e}")

        # Match command: count lines in file
        elif re.match(r'^count lines in (\S+)$', line):
            match = re.match(r'^count lines in (\S+)$', line)
            filename = match.group(1)
            try:
                with open(filename, 'r') as f:
                    lines = f.readlines()
                    print(f"File '{filename}' has {len(lines)} lines.")
            except FileNotFoundError:
                print(f"Error: File '{filename}' not found.")

        # Match command: copy file
        elif re.match(r'^copy (\S+) to (\S+)$', line):
            match = re.match(r'^copy (\S+) to (\S+)$', line)
            src = match.group(1)
            dst = match.group(2)
            try:
                os.system(f'cp {src} {dst}')
                print(f"Copied '{src}' to '{dst}'.")
            except Exception as e:
                print(f"Error copying '{src}': {e}")

        # Match command: make directory
        elif re.match(r'^make directory (\S+)$', line):
            match = re.match(r'^make directory (\S+)$', line)
            dirname = match.group(1)
            try:
                os.makedirs(dirname, exist_ok=True)
                print(f"Created directory '{dirname}'.")
            except Exception as e:
                print(f"Error creating directory '{dirname}': {e}")

        # Match command: move file
        elif re.match(r'^move (\S+) to (\S+)$', line):
            match = re.match(r'^move (\S+) to (\S+)$', line)
            src = match.group(1)
            dst = match.group(2)
            try:
                os.rename(src, dst)
                print(f"Moved '{src}' to '{dst}'.")
            except Exception as e:
                print(f"Error moving '{src}': {e}")

        # Match command: list files in current directory
        elif re.match(r'^list files$', line):
            try:
                files = os.listdir('.')
                print("Files in current directory:")
                for file in files:
                    print(file)
            except Exception as e:
                print(f"Error listing files: {e}")

        # Match command: list files in a directory
        elif re.match(r'^list files in (\S+)$', line):
            match = re.match(r'^list files in (\S+)$', line)
            dirname = match.group(1)
            try:
                files = os.listdir(dirname)
                print(f"Files in '{dirname}':")
                for file in files:
                    print(file)
            except Exception as e:
                print(f"Error listing files in '{dirname}': {e}")

        # Match command: find files containing specific text (in filename)
        elif re.match(r'^find files containing "(.+)"$', line):
            match = re.match(r'^find files containing "(.+)"$', line)
            text = match.group(1)
            try:
                files = os.listdir('.')
                print(f"Files containing '{text}' in their names:")
                for file in files:
                    if text in file:
                        print(file)
            except Exception as e:
                print(f"Error finding files: {e}")

        # Match command: delete file (with optional confirmation)
        elif re.match(r'^delete (\S+)(?: confirm)?$', line):
            match = re.match(r'^delete (\S+)(?: confirm)?$', line)
            filename = match.group(1)
            confirm = match.group(2) == 'confirm'
            if not confirm:
                print(f"Deletion not confirmed. File '{filename}' remains.")
            else:
                try:
                    os.remove(filename)
                    print(f"Deleted file '{filename}'.")
                except Exception as e:
                    print(f"Error deleting file '{filename}': {e}")

        # Default case for unknown command
        else:
            print(f"Unknown command: '{line}'")

