import os
import re

def run(source):
    """
    Processes a sequence of commands from the input source.

    Args:
        source (str): A string containing multiple lines, each representing a command.
    """
    lines = source.split('\n')
    for line in lines:
        line = line.strip()
        if not line:
            continue  # Skip empty lines

        if re.match(r'create file ([^"]+) with content "(.+)"', line):
            # Create a new file with specified content
            match = re.match(r'create file ([^"]+) with content "(.+)"', line)
            name = match.group(1)
            content = match.group(2)
            try:
                with open(name, 'w') as f:
                    f.write(content)
                print(f"File '{name}' created with content.")
            except Exception as e:
                print(f"Error creating file '{name}': {str(e)}")

        elif re.match(r'read file ([^"]+)', line):
            # Read and display content of a file
            match = re.match(r'read file ([^"]+)', line)
            name = match.group(1)
            try:
                with open(name, 'r') as f:
                    content = f.read()
                print(f"Content of '{name}':\n{content}")
            except FileNotFoundError:
                print(f"File '{name}' not found.")
            except Exception as e:
                print(f"Error reading file '{name}': {str(e)}")

        elif re.match(r'append "(.+)" to ([^"]+)', line):
            # Append text to a file
            match = re.match(r'append "(.+)" to ([^"]+)', line)
            text = match.group(1)
            name = match.group(2)
            try:
                with open(name, 'a') as f:
                    f.write(text + '\n')
                print(f"Appended '{text}' to '{name}'.")
            except FileNotFoundError:
                print(f"File '{name}' not found.")
            except Exception as e:
                print(f"Error appending to '{name}': {str(e)}")

        elif re.match(r'count lines in ([^"]+)', line):
            # Count the number of lines in a file
            match = re.match(r'count lines in ([^"]+)', line)
            name = match.group(1)
            try:
                with open(name, 'r') as f:
                    lines = f.readlines()
                print(f"Number of lines in '{name}': {len(lines)}")
            except FileNotFoundError:
                print(f"File '{name}' not found.")
            except Exception as e:
                print(f"Error counting lines in '{name}': {str(e)}")

        elif re.match(r'copy ([^"]+) to ([^"]+)', line):
            # Copy the content of one file to another
            match = re.match(r'copy ([^"]+) to ([^"]+)', line)
            src = match.group(1)
            dst = match
            dst = match.group(2)
            try:
                with open(src, 'r') as f:
                    content = f.read()
                with open(dst, 'w') as f:
                    f.write(content)
                print(f"File '{src}' copied to '{dst}'.")
            except FileNotFoundError:
                print(f"File '{src}' not found.")
            except Exception as e:
                print(f"Error copying from '{src}': {str(e)}")

        elif re.match(r'make directory ([^"]+)', line):
            # Create a new directory
            match = re.match(r'make directory ([^"]+)', line)
            name = match.group(1)
            try:
                os.makedirs(name, exist_ok=True)
                print(f"Directory '{name}' created.")
            except Exception as e:
                print(f"Error creating directory '{name}': {str(e)}")

        elif re.match(r'move ([^"]+) to ([^"]+)', line):
            # Move a file
            match = re.match(r'move ([^"]+) to ([^"]+)', line)
            src = match.group(1)
            dst = match.group(2)
            try:
                os.rename(src, dst)
                print(f"Moved '{src}' to '{dst}'.")
            except FileNotFoundError:
                print(f"File '{src}' not found.")
            except Exception as e:
                print(f"Error moving '{src}': {str(e)}")

        elif re.match(r'list files', line):
            # List all files in the current directory
            try:
                files = os.listdir('.')
                if not files:
                    print("(empty)")
                else:
                    print('\n'.join(files))
            except Exception as e:
                print(f"Error listing files: {str(e)}")

        elif re.match(r'list files in ([^"]+)', line):
            # List files in a specific directory
            match = re.match(r'list files in ([^"]+)', line)
            dir_name = match.group(1)
            if not os.path.isdir(dir_name):
                print(f"Directory '{dir_name}' does not exist.")
                continue
            try:
                files = os.listdir(dir_name)
                if not files:
                    print("(empty)")
                else:
                    print('\n'.join(files))
            except Exception as e:
                print(f"Error listing files in '{dir_name}': {str(e)}")

        elif re.match(r'find files containing "(.+)"', line):
            # Find files that contain a specific text
            match = re.match(r'find files containing "(.+)"', line)
            text = match.group(1)
            found = []
            try:
                for filename in os.listdir('.'):
                    if os.path.isfile(filename):
                        try:
                            with open(filename, 'r') as f:
                                if text in f.read():
                                    found.append(filename)
                        except Exception:
                            continue
                if not found:
                    print("(empty)")
                else:
                    print('\n'.join(found))
            except Exception as e:
                print(f"Error searching for text: {str(e)}")

        elif re.match(r'delete ([^"]+) confirm', line):
            # Delete a file only if the command includes 'confirm'
            match = re.match(r'delete ([^"]+) confirm', line)
            name = match.group(1)
            try:
                os.remove(name)
                print(f"File '{name}' deleted.")
            except FileNotFoundError:
                print(f"File '{name}' not found.")
            except Exception as e:
                print(f"Error deleting '{name}': {str(e)}")

        elif re.match(r'delete ([^"]+)', line):
            # Deny deletion without 'confirm'
            name = re.match(r'delete ([^"]+)', line).group(1)
            print("REFUSED. Use 'delete <filename> confirm' to delete.")

        elif re.match(r'if ([^"]+) exists then (.+) otherwise (.+)', line):
            # Conditional command execution
            match = re.match(r'if ([^"]+) exists then (.+) otherwise (.+)', line)
            file_name = match.group(1)
            then_cmd = match.group(2)
            else_cmd = match.group(3)

            if os.path.exists(file_name):
                print(f"Executing '{then_cmd}' because '{file_name}' exists.")
                # Execute then_cmd (simplified)
                # In a real system, this could be implemented via `eval`, `subprocess`, or a parser
