import os

def process_commands(lines):
    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Create file with content
        match = re.match(r'create file ([^"]+) with content "(.+)"', line)
        if match:
            filename = match.group(1)
            content = match.group(2)
            with open(filename, 'w') as f:
                f.write(content)

        # Read file
        elif re.match(r'read file ([^"]+)', line):
            filename = re.search(r'read file ([^"]+)', line).group(1)
            if os.path.isfile(filename):
                with open(filename, 'r') as f:
                    print(f.read())

        # Append to file
        elif re.match(r'append "(.+)" to ([^"]+)', line):
            text = re.search(r'append "(.+)" to ([^"]+)', line).group(1)
            filename = re.search(r'append "(.+)" to ([^"]+)', line).group(2)
            with open(filename, 'a') as f:
                f.write(text)

        # Copy file
        elif re.match(r'copy ([^ ]+) to ([^ ]+)', line):
            src = re.search(r'copy ([^ ]+) to ([^ ]+)', line).group(1)
            dest = re.search(r'copy ([^ ]+) to ([^ ]+)', line).group(2)
            if os.path.exists(src):
                with open(src, 'r') as f:
                    content = f.read()
                with open(dest, 'w') as f:
                    f.write(content)

        # Make directory
        elif re.match(r'make directory ([^ ]+)', line):
            dir_name = re.search(r'make directory ([^ ]+)', line).group(1)
            os.makedirs(dir_name, exist_ok=True)

        # Move file
        elif re.match(r'move ([^ ]+) to ([^ ]+)', line):
            src = re.search(r'move ([^ ]+) to ([^ ]+)', line).group(1)
            dest = re.search(r'move ([^ ]+) to ([^ ]+)', line).group(2)
            if os.path.exists(src):
                if os.path.isdir(dest):
                    new_dest = os.path.join(dest, os.path.basename(src))
                else:
                    new_dest = dest
                os.rename(src, new_dest)

        # Delete file or directory
        elif re.match(r'delete ([^ ]+)', line):
            filename = re.search(r'delete ([^ ]+)', line).group(1)
            if os.path.isfile(filename):
                os.remove(filename)
            elif os.path.isdir(filename):
                os.rmdir(filename)

        # Unknown command
        else:
            print(f"Unknown command: {line}")

