        # Match "delete <file_name>" (or) "delete <file_name> confirm"
        elif re.fullmatch(r'delete ([^"]+)([ ]+confirm)?', line):
            name = re.match(r'delete ([^"]+)([ ]+confirm)?', line).group(1)
            if not re.match(r'delete ([^"]+)([ ]+confirm)?', line).group(2) or os.path.isfile(name):
                print('REFUSED')
            else:
                if os.path.exists(name):
                    os.remove(name)

