                # Simplified conditional: if file exists
                if condition_part.startswith('if'):
                    condition_parts = condition_part.split()
                    if len(condition_parts) >= 2 and condition_parts[1] == 'exists':
                        filename = condition_parts[0]
                        if os.path.exists(filename):
                            execute_command(command)
                        else:
                            pass  # No action on false condition
            else:
                pass  # Invalid 'if' command

        else:
            # Handle other commands
            match = re.match(r'^create file (\S+)$', line)
            if match:
                filename = match.group(1)
                with open(filename, 'w') as f:
                    f.write('')
                print(f"File '{filename}' created.")
            elif re.match(r'^read file (\S+)$', line):
                filename = re.match(r'^read file (\S+)$', line).group(1)
                try:
                    with open(filename, 'r') as f:
                        content = f.read()
                    print(f"Content of '{filename}':\n{content}")
                except FileNotFoundError:
                    print(f"File not found: {filename}")
            elif re.match(r'^delete file (\S+)$', line):
                filename = re.match(r'^delete file (\S+)$', line).group(1)
                try:
                    os.remove(filename)
                    print(f"File '{filename}' deleted.")
                except FileNotFoundError:
                    print(f"File not found: {filename}")
            elif re.match(r'^list directory (\S+)$', line):
                dir_path = re.match(r'^list directory (\S+)$', line).group(1)
                try:
                    items = os.listdir(dir_path)
                    for item in items:
                        print(item)
                except FileNotFoundError:
                    print(f"Directory not found: {dir_path}")
