                src, dest = re.match(r'^copy file (\S+) (\S+)$', line).groups()
                try:
                    shutil.copy(src, dest)
                    print(f"File copied from '{src}' to '{dest}'.")
                except Exception as e:
                    print(f"Error copying file: {e}")
            elif re.match(r'^move file (\S+) (\S+)$', line):
                src, dest = re.match(r'^move file (\S+) (\S+)$', line).groups()
                try:
                    shutil.move(src, dest)
                    print(f"File moved from '{src}' to '{dest}'.")
                except Exception as e:
                    print(f"Error moving file: {e}")
            elif re.match(r'^rename file (\S+) (\S+)$', line):
                src, dest = re.match(r'^rename file (\S+) (\S+)$', line).groups()
                try:
                    os.rename(src, dest)
                    print(f"File renamed from '{src}' to '{dest}'.")
                except Exception as e:
                    print(f"Error renaming file: {e}")
            elif re.match(r'^chmod file (\S+) (\S+)$', line):
                filename, mode = re.match(r'^chmod file (\S+) (\S+)$', line).groups()
                try:
                    os.chmod(filename, int(mode, 8))
                    print(f"Permissions for '{filename}' changed to {mode}.")
                except Exception as e:
                    print(f"Error changing permissions: {e}")
            elif re.match(r'^touch file (\S+)$', line):
                filename = re.match(r'^touch file (\S+)$', line).group(1)
                try:
                    with open(filename, 'a') as f:
                        pass
                    print(f"File '{filename}' touched (created or updated).")
                except Exception as e:
                    print(f"Error touching file: {e}")
            elif re.match(r'^mkdir (\S+)$', line):
                dir_path = re.match(r'^mkdir (\S+)$', line).group(1)
                try:
                    os.makedirs(dir_path, exist_ok=True)
                    print(f"Directory '{dir_path}' created.")
                except Exception as e:
                    print(f"Error creating directory: {e}")
            elif re.match(r'^rmdir (\S+)$', line):
                dir_path = re.match(r'^rmdir (\S+)$', line).group(1)
                try:
                    os.rmdir(dir_path)
                    print(f"Directory '{dir_path}' removed.")
                except Exception as e:
                    print(f"Error removing directory: {e}")
            elif re.match(r'^cd (\S+)$', line):
                dir_path = re.match(r'^cd (\S+)$', line).group(1)
                try:
                    os.chdir(dir_path)
                    print(f"Current directory: {os.getcwd()}")
                except Exception as e:
                    print(f"Error changing directory: {e}")
            elif line == 'exit':
                print("Exiting command loop.")
                return
            else:
                print(f"Unknown command: {line}")

