    if command == 'create':
        if len(sys.argv) < 3:
            print("Usage: python script.py create <filename>")
            return
        filename = sys.argv[2]
        try:
            with open(filename, 'w') as f:
                pass  # Create an empty file
            print(f"File '{filename}' created.")
        except Exception as e:
            print(f"Error creating file '{filename}': {e}")

    elif command == 'read':
        if len(sys.argv) < 3:
            print("Usage: python script.py read <filename>")
            return
        filename = sys.argv[2]
        if not os.path.exists(filename):
            print(f"File '{filename}' does not exist.")
            return
        try:
            with open(filename, 'r') as f:
                content = f.read()
                print(content)
        except Exception as e:
            print(f"Error reading file '{filename}': {e}")

    elif command == 'write':
        if len(sys.argv) < 4:
            print("Usage: python script.py write <filename> <content>")
            return
        filename = sys.argv[2]
        content = ' '.join(sys.argv[3:])
        try:
            with open(filename, 'w') as f:
                f.write(content)
            print(f"Written content to '{filename}'.")
        except Exception as e:
            print(f"Error writing to file '{filename}': {e}")

    elif command == 'append':
        if len(sys.argv) < 4:
            print("Usage: python script.py append <filename> <content>")
            return
        filename = sys.argv[2]
        content = ' '.join(sys.argv[3:])
        try:
