                f.write(content)
            print(f"Appended content to '{filename}'.")
        except Exception as e:
            print(f"Error appending to file '{filename}': {e}")

    elif command == 'delete':
        if len(sys.argv) < 3:
            print("Usage: python script.py delete <filename>")
            return
        filename = sys.argv[2]
        if os.path.exists(filename):
            try:
                os.remove(filename)
                print(f"File '{filename}' deleted.")
            except Exception as e:
                print(f"Error deleting file '{filename}': {e}")
        else:
            print(f"File '{filename}' does not exist.")

    elif command == 'list':
