import sys

def process_line(line):
    if line.startswith('create file'):
        parts = line.split('with content "')
        if len(parts) >= 2:
            filename_part = parts[0].split(' ')[2]
            content = parts[1].split('"')[0]
            try:
                with open(filename_part, 'w') as f:
                    f.write(content)
                print(f"File '{filename_part}' created successfully.")
            except Exception as e:
                print(f"Error creating file: {e}")
    elif line.startswith('read file'):
        parts = line.split()
        if len(parts) >= 2:
            filename = parts[1]
            try:
                with open(filename, 'r') as f:
                    content = f.read()
                    print(f"Content of '{filename}':\n{content}")
            except Exception as e:
                print(f"Error reading file '{filename}': {e}")
    elif line.startswith('append'):
        parts = line.split()
        if len(parts) >= 2:
            filename = parts[1]
            content = ' '.join(parts[2:])
            try:
                with open(filename, 'a') as f:
                    f.write(content)
                print(f"Appended to '{filename}' successfully.")
            except Exception as e:
                print(f"Error appending to '{filename}': {e}")
    elif line.startswith('count lines in'):
        parts = line.split()
        if len(parts) >= 2:
            filename = parts[1]
            try:
                with open(filename, 'r') as f:
                    lines = f.readlines()
                    print(f"Number of lines in '{filename}': {len(lines)}")
            except Exception as e:
                print(f"Error counting lines in '{filename}': {e}")
    elif line.startswith('copy'):
        parts = line.split()
        if len(parts) >= 3:
            src = parts[1]
            dst = parts[2]
            try:
                shutil.copy(src, dst)
                print(f"Copied '{src}' to '{dst}' successfully.")
            except Exception as e:
                print(f"Error copying file: {e}")
    elif line.startswith('move'):
        parts = line.split()
        if len(parts) >= 3:
            src = parts[1]
            dst = parts[2]
            try:
                shutil.move(src, dst)
                print(f"Moved '{src}' to '{dst}' successfully.")
            except Exception as e:
                print(f"Error moving file: {e}")
    elif line.startswith('list files'):
        try:
            files = os.listdir('.')
            print("Files in current directory:")
            for file in sorted(files):
                print(f" - {file}")
        except Exception as e:
            print(f"Error listing files: {e}")
    elif line.startswith('find files containing'):
        parts = line.split()
        if len(parts) >= 2:
            text = parts[1].strip('"')
            try:
                files = os.listdir('.')
                matching_files = []
                for file in sorted(files):
                    if text in file:
                        matching_files.append(file)
                    else:
                        with open(file, 'r') as f:
                            content = f.read()
                            if text in content:
                                matching_files.append(file)
                print("Files containing text:")
                for file in matching_files:
                    print(f" - {file}")
            except Exception as e:
                print(f"Error searching for text: {e}")
    elif line.startswith('delete'):
        parts = line.split()
        if len(parts) >= 2:
            filename = parts[1]
            if 'confirm' in line:
                try:
                    os.remove(filename)
                    print(f"Deleted '{filename}' successfully.")
                except Exception as e:
                    print(f"Error deleting '{filename}': {e}")
            else:
                print(f"Warning: 'confirm' keyword missing. Deletion not performed.")
    else:
        print(f"Unknown command: {line}")

def main():
    # Read lines from stdin
    lines = [line.strip() for line in sys.stdin if line.strip()]

    # Process each line
    for line in lines:
        if line.startswith('if'):
            # Parse the conditional command
            condition_part, command_part = line.split(' then ')
            condition_part = condition_part.strip()
            command_part = command_part.strip()

            # Check if the condition is 'file exists'
            if condition_part.startswith('file exists'):
                filename = condition_part.split(' ')[1]
                if os.path.exists(filename):
                    # Execute the command part
                    for cmd_line in command_part.split('\n'):
                        process_line(cmd_line)
                else:
                    print(f"Condition failed: file '{filename}' does not exist.")
        else:
            process_line(line)

