            shutil.move(src, dest)
        elif intent == 'move' and 'confirm' in parts[-1]:
            src, dest = parts[0].split(' ')[1], ''.join(parts[-3:-1])
            os.rename(src, dest)

        elif intent == 'delete':
            name = parts[0].split('"')[0]
            if any(part == 'confirm' for part in parts):
                try:
                    os.remove(name)
                except FileNotFoundError as e:
                    print(f"Error deleting {name}: {e}")
            else:
                print('REFUSED')

        elif intent.startswith('if'):
            file, then_cmd, else_cmd = [part.split(' ')[1] for part in line.split(':')[1:]]
            if os.path.exists(file):
                run('\n'.join([file] + [then_cmd]))
            else:
                run('\n'.join([file] + [else_cmd]))

import os
import shutil

def run(source):
    cmds = source.split("\n")

    def execute_cmd(cmd):
        parts = cmd.split()
        if len(parts) == 0:
            return

        operation, *args = parts
        args = list(map(str.strip, args))

        if operation == "create file":
            filename, content = args[0], " ".join(args[1:])
            with open(filename, 'w') as f:
                f.write(content)

        elif operation in ["read file", "append"]:
            filename = args[0]
            if not os.path.exists(filename):
                print(f"File '{filename}' does not exist.")
                return

            with open(filename, 'r') as f:
                content = f.read()

            if operation == "read file":
                print(content)
            elif operation == "append":
                new_line = " ".join(args[1:])
                with open(filename, 'a') as f:
                    f.write(f"{new_line}\n")

        elif operation == "count lines in":
            filename = args[0]
            if not os.path.exists(filename):
                print(f"File '{filename}' does not exist.")
                return

            with open(filename, 'r') as f:
                lines = f.readlines()
            print(len(lines))

        elif operation in ["copy", "move"]:
            src, dest = args[:2]
            if not os.path.exists(src):
                print(f"Source file '{src}' does not exist.")
                return

            src_dir = os.path.dirname(src)
            dest_file = os.path.join(os.path.dirname(dest), os.path.basename(src))

            if operation == "move" and "confirm" in args[-1]:
                shutil.move(src, dest_file)
            elif operation == "copy":
                try:
                    shutil.copyfile(src, dest_file)
                except Exception as e:
                    print(f"Error {operation}: {e}")
            else:
                print("REFUSED")

        elif operation in ["make directory", "delete"]:
            dir_or_file = args[0]
            if "confirm" not in args[-1]:
                print("REFUSED")
                return

            if operation == "make directory":
                try:
                    os.makedirs(dir_or_file)
                except FileExistsError:
                    print(f"Directory '{dir_or_file}' already exists.")
            elif operation == "delete":
                try:
                    if os.path.isdir(dir_or_file):
                        shutil.rmtree(dir_or_file)
                    else:
                        os.remove(dir_or_file)
                except FileNotFoundError:
                    print(f"{dir_or_file} does not exist.")

        elif operation == "list files":
            dir = args[0] or "."
            files = sorted([os.path.join(dir, f) for f in os.listdir(dir)])
            print(*files, sep=" ")

        elif operation == "find files containing":
            text, dir = args[0], args[1] or "."
            matches = [f for f in os.listdir(dir) if text in f]
            print(*matches, sep=" ")

    for cmd in cmds:
        execute_cmd(cmd)

