            name, content = re.match(r'create file (.+) with content "(.+)"', line).groups()
            with open(name, 'w') as f:
                f.write(content)
            print(f"Created file: {name}")

        # Read file content
        elif re.fullmatch(r'read file (.+)', line):
            name = re.match(r'read file (.+)', line).group(1)
            try:
                with open(name, 'r') as f:
                    print(f.read())
            except FileNotFoundError:
                print(f"File not found: {name}")

        # Append text to a file
        elif re.fullmatch(r'append "(.+)" to (.+)', line):
            text, name = re.match(r'append "(.+)" to (.+)', line).groups()
            try:
                with open(name, 'a') as f:
                    f.write(text)
                print(f"Appended to {name}")
            except FileNotFoundError:
                print(f"File not found: {name}")

        # Copy a file
        elif re.fullmatch(r'copy (.+) to (.+)', line):
            src, dst = re.match(r'copy (.+) to (.+)', line).groups()
            try:
                shutil.copy(src, dst)
                print(f"Copied {src} to {dst}")
            except FileNotFoundError:
                print(f"File not found: {src}")

        # Move a file
        elif re.fullmatch(r'move (.+) to (.+)', line):
            src, dst = re.match(r'move (.+) to (.+)', line).groups()
            try:
                shutil.move(src, dst)
                print(f"Moved {src} to {dst}")
            except FileNotFoundError:
                print(f"File not found: {src}")

        # List files in a directory
        elif re.fullmatch(r'list files in (.+)', line):
            dir_path = re.match(r'list files in (.+)', line).group(1)
            try:
                files = os.listdir(dir_path)
                print("Files in", dir_path + ":")
                for file in files:
                    print(f" - {file}")
            except FileNotFoundError:
                print(f"Directory not found: {dir_path}")

        # Find files containing a specific string
        elif re.fullmatch(r'find files containing "(.+)"', line):
            text = re.match(r'find files containing "(.+)"', line).group(1)
            files = [f for f in os.listdir('.') if text in f]
            print("Files containing", text + ":")
            for file in files:
                print(f" - {file}")

        # Delete a file only if "confirm" is included
        elif re.fullmatch(r'delete (.+) (confirm)?', line):
            name = re.match(r'delete (.+) (confirm)?', line).group(1)
            confirm = re.match(r'delete (.+) (confirm)?', line).group(2) is not None
            if not confirm:
                print("REFUSED: Confirmation required.")
            else:
                try:
                    os.remove(name)
                    print(f"Deleted file: {name}")
                except FileNotFoundError:
                    print(f"File not found: {name}")

        else:
