import os
import shutil

def run(source):
    """
    Process a list of commands to perform file and directory operations.

    Args:
        source (str): A string containing multiple lines of commands, each on a new line.
    """
    lines = source.split('\n')
    for line in lines:
        line = line.strip()
        if not line:
            continue

        if line.startswith('create file'):
            # Parse the filename and content
            parts = line.split()
            filename = parts[2]
            content = parts[4].strip('"')
            with open(filename, 'w') as f:
                f.write(content)

        elif line.startswith('read'):
            # Read the content of a file
            parts = line.split()
            filename = parts[1]
            try:
                with open(filename, 'r') as f:
                    print(f.read())
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

        elif line.startswith('append'):
            # Append content to a file
            parts = line.split()
            content = parts[1].strip('"')
            filename = parts[3]
            try:
                with open(filename, 'a') as f:
                    f.write(content)
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

        elif line.startswith('count lines'):
            # Count the number of lines in a file
            parts = line.split()
            filename = parts[3]
            try:
                with open(filename, 'r') as f:
                    lines = f.readlines()
                    print(len(lines))
            except FileNotFoundError:
                print(f"File '{filename}' not found.")

        elif line.startswith('copy'):
            # Copy content from one file to another
            parts = line.split()
            src = parts[1]
            dest = parts[3]
            try:
                with open(src, 'r') as fsrc, open(dest, 'w') as fdest:
                    fdest.write(fsrc.read())
            except FileNotFoundError:
                print(f"File '{src}' not found.")

        elif line.startswith('make directory'):
            # Create a directory
            parts = line.split()
            dirname = parts[2]
            os.makedirs(dirname, exist_ok=True)

        elif line.startswith('move'):
            # Move a file to a directory
            parts = line.split()
            src = parts[1]
            dest = parts[3]
            try:
                shutil.move(src, dest)
            except FileNotFoundError:
                print(f"File '{src}' not found.")

        elif line.startswith('delete'):
            # Delete a file or refuse if no 'confirm' keyword is provided
            parts = line.split()
            if len(parts) >= 3 and parts[2] == 'confirm':
                filename = parts[1]
                try:
                    os.remove(filename)
                except FileNotFoundError:
                    print(f"File '{filename}' not found.")
            else:
                print("REFUSED")

        elif line.startswith('if'):
            # Execute a conditional block
            import re
            match = re.match(r'^if\s+(.*?)\s+then\s+(.*?)\s+otherwise\s+(.*)$', line)
            if not match:
                continue
            condition_part, then_part, else_part = match.groups()

            condition_parts = condition_part.split()
            filename = condition_parts[0]
            condition = condition_parts[1]

            try:
                if condition == 'exists' and os.path.exists(filename):
                    # Execute 'then' part
                    exec(then_part)
                elif condition == 'does not exist' and not os.path.exists(filename):
                    # Execute 'else' part
                    exec(else_part)
            except Exception as e:
                print(f"Error in conditional execution: {e}")

        else:
            # Unknown command
            print(f"Unknown command: {line}")

