def process_line(line):
    # Check for 'if' condition
    if line.startswith('if'):
        # Split the line into condition, then, and else parts
        parts = line.split(' then ')
        if len(parts) < 2:
            return

        if_part = parts[0]
        rest = parts[1]
        then_part, else_part = rest.split(' otherwise ', 1)

        # Extract the filename from the condition
        if_condition = if_part[3:].split(' exists')[0].strip()

        # Execute the appropriate branch
        if os.path.exists(if_condition):
            process_line(then_part)
        else:
            process_line(else_part)

    # Handle 'create file' command
    elif re.match(r'^create file (.+) with content "([^"]+)"$', line):
        match = re.match(r'^create file (.+) with content "([^"]+)"$', line)
        filename = match.group(1)
        content = match.group(2)
        try:
            with open(filename, 'w') as f:
                f.write(content)
        except Exception as e:
            print(f"Error creating file {filename}: {e}")

    # Handle 'read file' command
    elif re.match(r'^read file (.+)$', line):
        match = re.match(r'^read file (.+)$', line)
        filename = match.group(1)
        try:
            with open(filename, 'r') as f:
                print(f.read())
        except Exception as e:
            print(f"Error reading file {filename}: {e}")

import os

def run(source):
    # Keep track of files and directories created during execution
    created = set()

    def create_file(name, content="", is_dir=False):
        nonlocal created
        if not name:
            return
        if is_dir:
            os.makedirs(name, exist_ok=True)
            created.add(name)
        else:
            with open(name, "w") as f:
                f.write(content)
            created.add(name)

    def get_state(name):
        return os.path.exists(name) and name in created

    def read_file(name):
        if not get_state(name):
            return "REFUSED"
        with open(name, "r") as f:
            return f.read()

    def append_to_file(name, text):
        if not get_state(name):
            return "REFUSED"
        with open(name, "a") as f:
            f.write(f"\n{text}")

    def count_lines(name):
        if not get_state(name):
            return "REFUSED"
        with open(name, "r") as f:
            return len(list(filter(None, f.read().split("\n"))))

    def copy_file(src, dest):
        if not get_state(src) or src == dest:
            return "REFUSED"
        shutil.copy2(src, dest)
        created.add(dest)

    def move_file(src, dest):
        if not get_state(src) or src == dest:
            return "REFUSED"
        shutil.move(src, dest)
        created.remove(src)
        created.add(dest)

    def list_files():
        file_list = [f for f in os.listdir(".") if not f.startswith("._")]
        return " ".join(sorted(file_list))

    def find_files(pattern):
        matched_files = [f for f in os.listdir(".") if f.startswith("._") or (pattern in f and not f.startswith("._"))]
        return " ".join(sorted(matched_files[1:]))

    def delete_file(name):
        if not get_state(name):
            return "REFUSED"
        os.remove(name)
        created.remove(name)

    def execute_conditional(condition, then_intents, otherwise_intents):
        if os.path.exists(condition):
            for intent in then_intents:
                process_intent(intent)
        else:
            for intent in otherwise_intents:
                process_intent(intent)

    def process_intent(intent):
        lines = intent.splitlines()
        if len(lines) < 1:
            return

        command, *params = lines[0].strip().split(" ", maxsplit=2)
        if command in ("create", "make"):
            create_file(*params)
        elif command == "read":
            print(read_file(*params))
        elif command == "append":
            append_to_file(*params)
        elif command == "count":
            print(count_lines(*params))
        elif command == "copy":
            copy_file(*params)
        elif command == "move":
            move_file(*params)
        elif command == "list":
            print(list_files())
        elif command == "find":
            print(find_files(*params))
        elif command.endswith("confirm"):
            delete_file(*params[:-1])
        elif command in ("if", "then", "otherwise"):
            execute_conditional(*[lines[i].strip() for i in (1, 2, 3) if lines[i]])
        else:
            print("REFUSED")

    # Initialize the sandbox directory and change to it
    os.makedirs("._", exist_ok=True)
    os.chdir("._")

    for line in source.splitlines():
        process_intent(line)

