    if re.match(r'^append "([^"]+)" to (.+)$', line):
        text = line.split()[1].strip('"')
        filename = line.split()[3]
        try:
            with open(filename, 'a') as f:
                f.write(text + '\n')
            print(f"Appended text to '{filename}'.")
        except Exception as e:
            print(f"Error appending to '{filename}': {e}")
        return

    # Match 'copy file to file' command
    if re.match(r'^copy (.+) to (.+)$', line):
        src, dest = line.split()[1], line.split()[3]
        try:
            shutil.copy(src, dest)
            print(f"Copied '{src}' to '{dest}'.")
        except Exception as e:
            print(f"Error copying '{src}' to '{dest}': {e}")
        return

    # Match 'move file to file' command
    if re.match(r'^move (.+) to (.+)$', line):
        src, dest = line.split()[1], line.split()[3]
        try:
            shutil.move(src, dest)
            print(f"Moved '{src}' to '{dest}'.")
        except Exception as e:
            print(f"Error moving '{src}' to '{dest}': {e}")
        return

    # Match 'list files' command
    if re.match(r'^list files$', line):
        files = [f for f in os.listdir('.') if os.path.isfile(f)]
        if not files:
            print("(empty)")
        else:
            print("\n".join(files))
        return

    # Match 'list files in directory' command
    if re.match(r'^list files in (.+)$', line):
        dir_name = line.split()[2]
        if not os.path.exists(dir_name) or not os.path.isdir(dir_name):
            print("(empty)")
        else:
            files = [f for f in os.listdir(dir_name) if os.path.isfile(os.path.join(dir_name, f))]
            if not files:
                print("(empty)")
            else:
                print("\n".join(files))
        return

    # Match 'count lines in file' command
    if re.match(r'^count lines in (.+)$', line):
        filename = line.split()[2]
        try:
            with open(filename, 'r') as f:
                lines = f.readlines()
                print(f"Number of lines in '{filename}': {len(lines)}")
        except Exception as e:
            print(f"Error counting lines in '{filename}': {e}")
        return

    # Match 'delete file' command
    if re.match(r'^delete (.+)$', line):
        filename = line.split()[1]
        print("REFUSED")
        return

    # Match 'delete file confirm' command
    if re.match(r'^delete (.+) confirm$', line):
        filename = line.split()[1]
        try:
            os.remove(filename)
            print(f"Deleted '{filename}'.")
        except Exception as e:
            print(f"Error deleting '{filename}': {e}")
        return

    # Match 'find files containing text' command
    if re.match(r'^find files containing "([^"]+)"$', line):
        text = line.split()[2].strip('"')
        files = []
        for filename in os.listdir('.'):
            if os.path.isfile(filename):
                try:
                    with open(filename, 'r') as f:
                        if text in f.read():
