                results.append(' '.join(sorted(files)))
            elif command == 'count':
                filename = read_match.group(3)
                try:
                    results.append(str(sum(1 for _ in open(filename, "rb"))))
                except FileNotFoundError:
                    print(f"File {filename} not found")
            elif command == 'find':
                filename = read_match.group(3)
                if not filename:
                    results.append('(none)')
                    continue
                match_files = [f for f in os.listdir() if re.search(rf'\b{filename}\b', f)]
                results.append(' '.join(match_files))
            continue

        # --- 2. File Manipulation / Advanced Commands ---
        copy_match = re.match(r'^copy (.+?) to (.+)$', line)
        if copy_match:
            src_filename = copy_match.group(1)
            dest_filename = copy_match.group(2)
            shutil.copyfile(src_filename, dest_filename)
            continue

        # Make directory and move file/directory operations
        make_dir_or_move_match = re.match(r'^make directory (.+)|move (.+) to (.+)$', line)
        if make_dir_or_move_match:
            if make_dir_or_move_match.group(1):
                dirname = make_dir_or_move_match.group(1)
                os.makedirs(dirname, exist_ok=True)
            else:
                src_filename, dest_filename = map(str, make_dir_or_move_match.groups())
                shutil.move(src_filename, dest_filename)

    # Print results for read/list/count/find intents
    for result in results:
        print(result)

