import re
import os

def run(source):
    lines = source.strip().split('\n')
    results = []

    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Create a file
        create_match = re.match(r'^create file (.+?) with content "(.+)"$', line)
        if create_match:
            filename = create_match.group(1)
            content = create_match.group(2)
            try:
                with open(filename, 'w') as f:
                    f.write(content)
            except Exception as e:
                print(f"Error: {e}")
            continue

        # Delete a file
        delete_match = re.match(r'^delete (.+?)?( confirm)?$', line)
        if delete_match:
            filename = delete_match.group(1)
            confirm = delete_match.group(2)
            if not confirm:
                print("REFUSED")
                continue
            try:
                os.remove(filename)
            except FileNotFoundError:
                print(f"File {filename} not found")
            continue

        # List, read, or count files
        read_match = re.match(r'^read|list|count (.+?)?( in )?(.+)?$', line)
        if read_match:
            command = read_match.group(1)
            path = read_match.group(3)
            if command == 'read':
                filename = path
                try:
                    with open(filename, 'r') as f:
                        results.append(f.read())
                except FileNotFoundError:
                    print(f"File {filename} not found")
            elif command == 'list':
                if path:
                    files = os.listdir(path)
                else:
                    files = os.listdir('.')
                print(' '.join(sorted(files)) if files else '(empty)')
            elif command == 'count':
                filename = path
                try:
                    with open(filename, 'r') as f:
                        lines = f.readlines()
                        print(len(lines))
                except FileNotFoundError:
                    print(f"File {filename} not find")
            continue

        # Find files containing text
        find_match = re.match(r'^find files containing "(.+)"$', line)
        if find_match:
            text = find_match.group(1)
            matches = []
            for file in os.listdir('.'):
                try:
                    if text in open(file).read():
                        matches.append(file)
                except:
                    pass
            print(' '.join(sorted(matches)) if matches else '(none)')
            continue

        # Make directory
        make_dir_match = re.match(r'^make directory (.+)$', line)
        if make_dir_match:
            dir_name = make_dir_match.group(1)
            try:
                os.makedirs(dir_name, exist_ok=True)
            except Exception as e:
                print(f"Error: {e}")
            continue

        # Move file
        move_match = re.match(r'^move (.+) to (.+)$', line)
        if move_match:
            src = move_match.group(1)
            dest = move_match.group(2)
            try:
                os.rename(src, dest)
            except FileNotFoundError:
                print(f"Error: Source file {src} not found")
            except Exception as e:
                print(f"Error: {e}")
            continue

        # If conditional
        if_match = re.match(r'^if (.+?) exists then (.+?) otherwise (.+)$', line)
        if if_match:
            condition = if_match.group(1)
            then = if_match.group(2)
            else_case = if_match.group(3)
            try:
                if os.path.exists(condition):
                    exec(then)
                else:
                    exec(else_case)
            except Exception as e:
                print(f"Error in conditional: {e}")
            continue

        # Unknown command
        print(f"Unknown command: {line}")

import os
import re
import sys

def process_input(line):
    line = line.strip()
    if not line:
        return

    # Match 'make directory'
    make_dir_match = re.match(r'^make directory (.+)$', line)
    if make_dir_match:
        dir_name = make_dir_match.group(1)
        os.makedirs(dir_name, exist_ok=True)
        print(f"Directory '{dir_name}' created or exists.")
        return

    # Match 'move'
    move_match = re.match(r'^move (.+) to (.+)$', line)
    if move_match:
        src, dest = move_match.groups()
        if not os.path.exists(src):
            print(f"Error: Source file '{src}' not found.")
            return

        if os.path.isdir(dest):
            new_dest = os.path.join(dest, os.path.basename(src))
            try:
                os.rename(src, new_dest)
                print(f"Moved '{src}' to '{new_dest}'.")
            except Exception as e:
                print(f"Error: {e}")
        else:
            try:
                os.rename(src, dest)
                print(f"Moved '{src}' to '{dest}'.")
            except Exception as e:
                print(f"Error: {e}")
        return

    # Match 'delete'
    delete_match = re.match(r'^delete (.+) (confirm)?$', line)
    if delete_match:
        file_name = delete_match.group(1)
        confirm = delete_match.group(2) == 'confirm'

        if not confirm:
            print("Cannot delete without confirmation.")
            return

        if not os.path.exists(file_name):
            print(f"File '{file_name}' not found.")
            return

        try:
            os.remove(file_name)
            print(f"File '{file_name}' deleted.")
        except Exception as e:
            print(f"Error: {e}")
        return

    # Match 'list files in'
    list_match = re.match(r'^list files in (.+)$', line)
    if list_match:
        dir_name = list_match.group(1)
        if not os.path.isdir(dir_name):
            print(f"Directory '{dir_name}' does not exist.")
            return

        try:
            files = os.listdir(dir_name)
            if files:
                print(f"Files in '{dir_name}':")
                for f in files:
                    print(f"  - {f}")
            else:
                print(f"Directory '{dir_name}' is empty.")
        except Exception as e:
            print(f"Error: {e}")
        return

    # Match 'find'
    find_match = re.match(r'^find (.+)$', line)
    if find_match:
        pattern = find_match.group(1)
        try:
            files = [f for f in os.listdir('.') if pattern in f]
            if files:
                print(f"Files containing '{pattern}':")
                for f in files:
                    print(f"  - {f}")
            else:
                print(f"No files found containing '{pattern}'.")
        except Exception as e:
            print(f"Error: {e}")
        return

    # Match 'if'
    if_match = re.match(r'^if (.+) exists then (.+) otherwise (.+)$', line)
    if if_match:
        file_name, then_cmd, else_cmd = if_match.groups()
        if os.path.exists(file_name):
            process_input(then_cmd)
        else:
            process_input(else_cmd)
        return

    # Unknown command
    print(f"Unknown command: '{line}'")

def main():
    print("Welcome to the File Manager. Type 'exit' to quit.")
    while True:
        line = input("> ")
        if line.lower() == 'exit':
            print("Exiting File Manager. Goodbye!")
            break
        process_input(line)

if __name__ == "__main__":
    main()

