import re

def run(source):
    lines = source.strip().split('\n')
    for line in lines:
        process_intent(line)

def process_intent(intent):
    if intent.startswith("create file"):
        _, filename, content = re.match(r'create file (\S+) with content "(.*)"', intent).groups()
        with open(filename, 'w') as f:
            f.write(content)
    elif intent.startswith("read file"):
        _, filename = re.match(r'read file (\S+)', intent).groups()
        with open(filename, 'r') as f:
            print(f.read().strip())
    elif intent.startswith("append"):
        _, text, filename = re.match(r'append "(.*)" to (\S+)', intent).groups()
        with open(filename, 'a') as f:
            f.write(text + '\n')
    elif intent.startswith("count lines in"):
        _, filename = re.match(r'count lines in (\S+)', intent).groups()
        with open(filename, 'r') as f:
            lines = f.readlines()
            print(len(lines))
    elif intent.startswith("copy"):
        _, src, dest = re.match(r'copy (\S+) to (\S+)', intent).groups()
        shutil.copy(src, dest)
    elif intent.startswith("make directory"):
        _, dirname = re.match(r'make directory (\S+)', intent).groups()
        os.makedirs(dirname, exist_ok=True)
    elif intent.startswith("move"):
        _, src, dest = re.match(r'move (\S+) to (\S+)', intent).groups()
        if os.path.isdir(dest):
            dest = os.path.join(dest, os.path.basename(src))
        shutil.move(src, dest)
    elif intent.startswith("list files"):
        if ' in ' in intent:
            _, dirname = re.match(r'list files in (\S+)', intent).groups()
            files = sorted(os.listdir(dirname))
        else:
            files = sorted(os.listdir('.'))
        if files:
            print(' '.join(files))
        else:
            print("(empty)")
    elif intent.startswith("find files containing"):
        _, text = re.match(r'find files containing "(.*)"', intent).groups()
        matches = []
        for root, _, files in os.walk('.'):
            for file in files:
                filepath = os.path.join(root, file)
                with open(filepath, 'r') as f:
                    if text in f.read():
                        matches.append(file)
        if matches:
            print(' '.join(sorted(matches)))
        else:
            print("(none)")
    elif intent.startswith("delete"):
        _, filename, confirm = re.match(r'delete (\S+) (confirm)?', intent).groups()
        if confirm:
            if os.path.exists(filename):
                if os.path.isfile(filename):
                    os.remove(filename)
                elif os.path.isdir(filename):
                    shutil.rmtree(filename)
        else:
            print("REFUSED")
    elif intent.startswith("if"):
        _, filename, then_intent, else_intent = re.match(r'if (\S+) exists then (.*) otherwise (.*)', intent).groups()
        if os.path.exists(filename):
            process_intent(then_intent)
        else:
            process_intent(else_intent)
    else:
        raise ValueError(f"Unknown intent: {intent}")

