import re
from collections import defaultdict

def translate(source):
    lines = source.strip().split('\n')
    script = []
    context = defaultdict(list)

    def emit(cmd):
        script.append(cmd)

    def parse_step(line):
        match = re.match(r'(\w+(?: \w+)*?) (?:with content "([\s\S]*?)"|containing "([\s\S]*?)"|confirm)?', line)
        if not match:
            raise ValueError(f"Invalid line: {line}")
        return match.groups()

    def process_create_file(step):
        name, content, _ = step
        emit(f'echo -n "{content}" > {name}')

    def process_read_file(step):
        name, _, _ = step
        emit(f'cat {name}')

    def process_append(step):
        name, content, _ = step
        emit(f'echo "{content}" >> {name}')

    def process_count_lines(step):
        name, _, _ = step
        emit(f'wc -l {name} | awk \'{{print $1}}\'')

    def process_copy(step):
        name, name2, _ = step
        emit(f'cp {name} {name2}')

    def process_make_directory(step):
        name, _, _ = step
        emit(f'mkdir {name}')

    def process_move(step):
        name, dest, _ = step
        emit(f'mv {name} {dest}')

    def process_list_files(step):
        _, _, dir = step
        dir = dir if dir else '.'
        emit(f'ls {dir} | tr "\\n" " " | sed \'s/ $/\\n/\' || echo "(empty)"')

    def process_find_files(step):
        _, _, text = step
        emit(f'grep -lR "{text}" . | tr "\\n" " " | sed \'s/ $/\\n/\' || echo "(none)"')

    def process_delete(step):
        name, _, confirm = step
        if confirm:
            emit(f'rm {name}')
        else:
            emit('echo REFUSED')

    def process_decision(step):
        name, then_intent, else_intent = step
        emit(f'if [ -f {name} ]; then')
        script.extend(translate(then_intent).split('\n'))
        emit('else')
        script.extend(translate(else_intent).split('\n'))
        emit('fi')

    for line in lines:
        step = parse_step(line)
        if line.startswith('create file'):
            process_create_file(step)
        elif line.startswith('read file'):
            process_read_file(step)
        elif line.startswith('append'):
            process_append(step)
        elif line.startswith('count lines in'):
            process_count_lines(step)
        elif line.startswith('copy'):
            process_copy(step)
        elif line.startswith('make directory'):
            process_make_directory(step)
        elif line.startswith('move'):
            process_move(step)
        elif line.startswith('list files'):
            process_list_files(step)
        elif line.startswith('find files containing'):
            process_find_files(step)
        elif line.startswith('delete'):
            process_delete(step)
        elif line.startswith('if'):
            process_decision(step)
        else:
            raise ValueError(f"Unknown command: {line}")

    return '\n'.join(script)

